1	import { describe, test, expect } from "vitest"
2	import type { Workflow, WorkflowCost, CostConfig } from "../types"
3	import { computeCost, validateAllocation, getWorkerType, getHeadcount } from "../types"
4	import { engagement as eyEngagement } from "../ey/engagement"
5	import { engagementCost as eyCost, costConfig as eyConfig } from "../ey/cost"
6	import { engagement as scEngagement } from "../superaudit/engagement"
7	import { engagementCost as scCost, costConfig as scConfig } from "../superaudit/cost"
8	import { requirements } from "../requirements"
9	
10	// ---- Helpers ----
11	
12	function collectLeaves(w: Workflow): Workflow[] {
13	  if (!w.sub_workflows?.length) return [w]
14	  return w.sub_workflows.flatMap(collectLeaves)
15	}
16	
17	function collectAll(w: Workflow): Workflow[] {
18	  return [w, ...(w.sub_workflows ?? []).flatMap(collectAll)]
19	}
20	
21	function collectAllCosts(wc: WorkflowCost): WorkflowCost[] {
22	  return [wc, ...(wc.sub_workflow_costs ?? []).flatMap(collectAllCosts)]
23	}
24	
25	// ---- Engagement test data ----
26	
27	const engagements = [
28	  {
29	    name: "EY",
30	    engagement: eyEngagement,
31	    engagementCost: eyCost,
32	    costConfig: eyConfig,
33	    expectedHoursRange: [160_000, 230_000],
34	    expectedCostRange: [15_000_000, 50_000_000],
35	    expectedHeadcountRange: [250, 600],
36	  },
37	  {
38	    name: "Superaudit",
39	    engagement: scEngagement,
40	    engagementCost: scCost,
41	    costConfig: scConfig,
42	    expectedHoursRange: [3_000, 6_000],
43	    expectedCostRange: [10_000_000, 18_000_000],
44	    expectedHeadcountRange: [30, 100],
45	  },
46	]
47	
48	// ---- Tests ----
49	
50	describe.each(engagements)("$name engagement", ({
51	  engagement, engagementCost, costConfig,
52	  expectedHoursRange, expectedCostRange, expectedHeadcountRange,
53	}) => {
54	  const computed = computeCost(engagementCost, costConfig)
55	  const allWorkflows = collectAll(engagement)
56	  const leaves = collectLeaves(engagement)
57	  const allCosts = collectAllCosts(computed)
58	  const parentCosts = allCosts.filter(wc => wc.sub_workflow_costs?.length)
59	
60	  // --- Structural ---
61	
62	  describe("structural", () => {
63	    test("WorkflowCost tree mirrors Workflow tree", () => {
64	      function checkMirror(wc: WorkflowCost, w: Workflow): void {
65	        expect(wc.workflow.id).toBe(w.id)
66	        const wcChildren = wc.sub_workflow_costs ?? []
67	        const wChildren = w.sub_workflows ?? []
68	        expect(wcChildren.length).toBe(wChildren.length)
69	        for (let i = 0; i < Math.min(wcChildren.length, wChildren.length); i++) {
70	          checkMirror(wcChildren[i], wChildren[i])
71	        }
72	      }
73	      checkMirror(engagementCost, engagement)
74	    })
75	
76	    test("parent timing spans children", () => {
77	      const parents = allWorkflows.filter(w => w.sub_workflows?.length)
78	      for (const p of parents) {
79	        const childTimings = p.sub_workflows!.filter(c => c.timing).map(c => c.timing!)
80	        if (!childTimings.length || !p.timing) continue
81	        const minStart = Math.min(...childTimings.map(t => t.start))
82	        const maxEnd = Math.max(...childTimings.map(t => t.end))
83	        expect(p.timing.start, `${p.id}: start`).toBeLessThanOrEqual(minStart)
84	        expect(p.timing.end, `${p.id}: end`).toBeGreaterThanOrEqual(maxEnd)
85	      }
86	    })
87	
88	    test("no dangling inputs", () => {
89	      const EXTERNAL = new Set([
90	        "PriorYearFile", "PublicFilings", "IndustryContext", "FinancialData",
91	        "EntityStructure", "GovernanceDocuments", "ControlDocumentation",
92	        "ControlPopulationData", "ComponentWorkpapers",
93	      ])
94	      const allOutputs = new Set<string>()
95	      for (const w of allWorkflows) for (const o of w.outputs ?? []) allOutputs.add(o)
96	      for (const w of allWorkflows) {
97	        for (const inp of w.inputs ?? []) {
98	          expect(allOutputs.has(inp) || EXTERNAL.has(inp), `${w.id} requires "${inp}"`).toBe(true)
99	        }
100	      }
101	    })
102	
103	    test("no DAG cycles", () => {
104	      const outputToProducer = new Map<string, string[]>()
105	      for (const w of allWorkflows) for (const o of w.outputs ?? []) {
106	        if (!outputToProducer.has(o)) outputToProducer.set(o, [])
107	        outputToProducer.get(o)!.push(w.id)
108	      }
109	      const adj = new Map<string, Set<string>>()
110	      for (const w of allWorkflows) {
111	        adj.set(w.id, new Set())
112	        for (const inp of w.inputs ?? []) {
113	          for (const producer of outputToProducer.get(inp) ?? []) {
114	            if (producer !== w.id) adj.get(w.id)!.add(producer)
115	          }
116	        }
117	      }
118	      const WHITE = 0, GRAY = 1, BLACK = 2
119	      const color = new Map<string, number>()
120	      for (const w of allWorkflows) color.set(w.id, WHITE)
121	      const cycles: string[] = []
122	      const stack: string[] = []
123	      function dfs(u: string) {
124	        color.set(u, GRAY); stack.push(u)
125	        for (const v of adj.get(u) ?? []) {
126	          if (color.get(v) === GRAY) cycles.push(stack.slice(stack.indexOf(v)).join(" → "))
127	          else if (color.get(v) === WHITE) dfs(v)
128	        }
129	        stack.pop(); color.set(u, BLACK)
130	      }
131	      for (const w of allWorkflows) if (color.get(w.id) === WHITE) dfs(w.id)
132	      expect(cycles, `Cycles found: ${cycles.join("; ")}`).toHaveLength(0)
133	    })
134	
135	    test("overhead categories sum to total_rate", () => {
136	      const categorySum = costConfig.overhead.categories.reduce((s, c) => s + c.rate, 0)
137	      expect(Math.abs(costConfig.overhead.total_rate - categorySum)).toBeLessThan(0.002)
138	    })
139	
140	    test("unique IDs across engagement", () => {
141	      const ids = allWorkflows.map(w => w.id)
142	      const dupes = ids.filter((id, i) => ids.indexOf(id) !== i)
143	      expect(dupes, `Duplicate IDs: ${dupes.join(", ")}`).toHaveLength(0)
144	    })
145	  })
146	
147	  // --- Per-leaf ---
148	
149	  describe("per-leaf", () => {
150	    const leafData = leaves.map(l => ({ id: l.id, leaf: l }))
151	
152	    describe.each(leafData)("$id", ({ leaf }) => {
153	      test("has agents (human and/or ai)", () => {
154	        const hasHuman = leaf.agents.human?.team && Object.keys(leaf.agents.human.team).length > 0
155	        const hasAi = !!leaf.agents.ai
156	        expect(hasHuman || hasAi, "no agents defined").toBe(true)
157	      })
158	
159	      test("all team roles exist in CostConfig", () => {
160	        const configRoles = new Set(costConfig.role_rates.map(r => r.role))
161	        if (!leaf.agents.human?.team) return
162	        for (const role of Object.keys(leaf.agents.human.team)) {
163	          expect(configRoles.has(role), `role "${role}" not in CostConfig`).toBe(true)
164	        }
165	      })
166	
167	      test("allocation ∈ (0, 1] for all roles", () => {
168	        if (!leaf.agents.human?.team) return
169	        for (const [role, alloc] of Object.entries(leaf.agents.human.team)) {
170	          if (typeof alloc === "object") {
171	            expect(alloc.allocation, `${role} allocation`).toBeGreaterThan(0)
172	            expect(alloc.allocation, `${role} allocation`).toBeLessThanOrEqual(1)
173	          }
174	        }
175	      })
176	
177	      test("count > 0 for all roles", () => {
178	        if (!leaf.agents.human?.team) return
179	        for (const [role, alloc] of Object.entries(leaf.agents.human.team)) {
180	          const count = typeof alloc === "number" ? alloc : alloc.count
181	          expect(count, `${role} count`).toBeGreaterThan(0)
182	        }
183	      })
184	
185	      test("has timing with start < end", () => {
186	        expect(leaf.timing, "missing timing").toBeDefined()
187	        if (leaf.timing) {
188	          expect(leaf.timing.end, "end must be > start").toBeGreaterThan(leaf.timing.start)
189	        }
190	      })
191	    })
192	  })
193	
194	  // --- Allocation ---
195	
196	  describe("allocation", () => {
197	    test("no role over-allocated in any week", () => {
198	      const report = validateAllocation(engagement, costConfig)
199	      if (!report.valid) {
200	        const summary = report.violations.slice(0, 5).map(v =>
201	          `week ${v.week}: ${v.role} allocated=${v.allocated}, available=${v.available}`
202	        ).join("; ")
203	        expect.fail(`${report.violations.length} violations: ${summary}`)
204	      }
205	    })
206	  })
207	
208	  // --- Cost fractals ---
209	
210	  describe("cost", () => {
211	    test("cost fractal: parent total = sum(children)", () => {
212	      for (const p of parentCosts) {
213	        const childTotal = p.sub_workflow_costs!.reduce((s, c) => s + c.total, 0)
214	        expect(Math.abs(p.total - childTotal), `${p.workflow.id}`).toBeLessThan(0.01)
215	      }
216	    })
217	
218	    test("hours fractal: parent computed_hours = sum(children)", () => {
219	      for (const p of parentCosts) {
220	        const childHours = p.sub_workflow_costs!.reduce((s, c) => s + c.computed_hours, 0)
221	        expect(Math.abs(p.computed_hours - childHours), `${p.workflow.id}`).toBeLessThan(0.01)
222	      }
223	    })
224	
225	    test("total cost in plausible range", () => {
226	      expect(computed.total).toBeGreaterThan(expectedCostRange[0])
227	      expect(computed.total).toBeLessThan(expectedCostRange[1])
228	    })
229	
230	    test("computed hours in plausible range", () => {
231	      expect(computed.computed_hours).toBeGreaterThan(expectedHoursRange[0])
232	      expect(computed.computed_hours).toBeLessThan(expectedHoursRange[1])
233	    })
234	  })
235	
236	  // --- PCAOB ---
237	
238	  describe("pcaob", () => {
239	    test("all requirement_ids reference valid IDs", () => {
240	      const validIds = new Set(requirements.map(r => r.id))
241	      for (const w of allWorkflows) {
