253	      const missing = requirements.map(r => r.id).filter(id => !covered.has(id))
254	      expect(missing, `Missing: ${missing.join(", ")}`).toHaveLength(0)
255	    })
256	  })
257	
258	  // --- Apple-specific ---
259	
260	  describe("apple-specific", () => {
261	    test("no manufacturing-primary language", () => {
262	      const mfgTerms = ["inventory observation", "manufacturing cost", "factory walkthrough", "production cost accounting"]
263	      for (const w of allWorkflows) {
